// Orchestrator: Central config + routing decisions.
// Routing logic lives here — no separate Route IF nodes.
// All downstream nodes reference config via $('Orchestrator').first().json.config

return [{
  json: {
    config: {
      // Source enables — controls which agents run
      gmailEnabled: true,
      calendarEnabled: true,
      slackEnabled: true,

      // Source settings
      gmailLimit: 10,
      slackQuery: 'in:#your-channel after:2d',
      calendarEmail: '<__PLACEHOLDER_VALUE__Your Google Calendar email address (e.g., you@gmail.com)__>',
      outputChannelId: 'YOUR_OUTPUT_CHANNEL_ID',

      // Temporal context
      dateLabel: $now.toFormat('EEEE, MMMM d, yyyy'),
      runTimestamp: new Date().toISOString(),

      // User profile — injected into all agent prompts
      userProfile: {
        name: 'Your Name',
        role: 'Product Manager',
        team: 'Your Team',
        vipContacts: ['CONFIGURE: add your VIP contacts here'],
        focusAreas: ['roadmap', 'prioritization', 'stakeholder alignment', 'sprint planning']
      }
    }
  }
}];

// Guardrails: Validate context before agents run.
// Checks for required config values and enforces content policies.
// In production: also checks rate limits, token budgets, content safety rules.

const config = $('Orchestrator').first().json.config;

const warnings = [];
if (!config.outputChannelId || config.outputChannelId === 'YOUR_OUTPUT_CHANNEL_ID') {
  warnings.push('Output channel not configured — update outputChannelId in Orchestrator');
}
if (!config.userProfile?.name || config.userProfile.name === 'Your Name') {
  warnings.push('User profile not configured — using defaults');
}
if (!config.gmailEnabled && !config.slackEnabled && !config.calendarEnabled) {
  warnings.push('All sources disabled — digest will be empty');
}

if (warnings.length > 0) {
  console.log('Guardrail warnings:', warnings);
}

return [{ json: { ...($input.first().json), guardrailWarnings: warnings } }];

// State Management: Load and track state across workflow runs.
// History context comes from Format History node (Google Sheets -> formatted summary).

const config = $('Guardrails').first().json.config;
const previousDigestSummary = $input.first().json.previousDigestSummary;

return [{
  json: {
    config,
    previousDigestSummary,
    sessionId: `digest-${Date.now()}`
  }
}];

