// Aggregate Agent Outputs: Combine all 3 agent digests into one item
// so the Synthesizer receives a single, structured input.
// Items in order after merge: [0] Gmail Agent, [1] Slack Agent, [2+] Calendar Agent

const items = $input.all();

const email_digest = (items[0]?.json?.output || '').trim() || 'No email data available.';
const slack_digest = (items[1]?.json?.output || '').trim() || 'No Slack data available.';

const calItems = items.slice(2);
const gcal_digest = calItems.length > 0
  ? calItems.map(i => (i?.json?.output || '').trim()).filter(s => s.length > 0).join('\n---\n')
  : 'No calendar data available.';

return [{ json: { email_digest, slack_digest, gcal_digest } }];

