// Format History: Collapses Sheets rows into a single summary string.
// Always outputs exactly 1 item so State Management runs even when the sheet is empty.

const rows = $input.all();

const prevDigests = rows
  .filter(r => r.json['Date'] && r.json['Digest'])
  .slice(-7)
  .map(r => `[${r.json['Date']}] ${r.json['Digest']}`)
  .join('\n\n---\n\n');

return [{
  json: {
    previousDigestSummary: prevDigests || 'No previous digests available — all items will be tagged [New].'
  }
}];
